package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreHeaderCase() {
        // Given
        boolean ignoreHeaderCase = true;
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withIgnoreHeaderCase(ignoreHeaderCase);

        // Then
        assertTrue(result.getIgnoreHeaderCase());
    }

    @Test
    public void testWithIgnoreHeaderCase_ReturnsNewInstance() {
        // Given
        boolean ignoreHeaderCase = true;
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withIgnoreHeaderCase(ignoreHeaderCase);

        // Then
        assertNotSame(csvFormat, result);
    }

    @Test
    public void testWithIgnoreHeaderCase_Reflection() {
        // Given
        boolean ignoreHeaderCase = true;
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = null;
        try {
            Method method = CSVFormat.class.getDeclaredMethod("withIgnoreHeaderCase", boolean.class);
            method.setAccessible(true);
            result = (CSVFormat) method.invoke(csvFormat, ignoreHeaderCase);
        } catch (NoSuchMethodException | IllegalAccessException | InvocationTargetException e) {
            fail("Exception thrown while invoking private method with reflection: " + e.getMessage());
        }

        // Then
        assertTrue(result.getIgnoreHeaderCase());
    }
}
